// Look up a lead by name or phone in mock CRM data.
// In production, this would query your actual CRM API.

const mockLeads = [
  {
    name: 'John Smith',
    phone: '903-555-0100',
    status: 'New Lead',
    lastContact: '2026-03-24',
    interest: '3BR Jessup single-section',
    nextStep: 'Schedule lot visit',
    assignedTo: 'Mike (Sales)'
  },
  {
    name: 'Maria Garcia',
    phone: '903-555-0200',
    status: 'Finance Review',
    lastContact: '2026-03-22',
    interest: 'Titanium 4BR multi-section',
    nextStep: 'Waiting on FHA pre-approval',
    assignedTo: 'Sarah (Finance)'
  },
  {
    name: 'Robert Johnson',
    phone: '903-555-0300',
    status: 'Appointment Set — Mar 28',
    lastContact: '2026-03-25',
    interest: 'Jessup 2BR starter home',
    nextStep: 'Lot walkthrough Friday 10 AM',
    assignedTo: 'Mike (Sales)'
  }
];

const body = $input.first().json.body || $input.first().json;
const searchName = (body.name || '').toLowerCase();
const searchPhone = (body.phone || '').replace(/\D/g, '');

const match = mockLeads.find(lead => {
  const nameMatch = lead.name.toLowerCase().includes(searchName);
  const phoneMatch = lead.phone.replace(/\D/g, '') === searchPhone;
  return (searchName && nameMatch) || (searchPhone && phoneMatch);
});

if (match) {
  return [{ json: { found: true, lead: match } }];
} else {
  return [{ json: { found: false, message: `No lead found matching name "${body.name}" or phone "${body.phone}".` } }];
}

// Format the lookup result as a customer-friendly status message.

const data = $input.first().json;

if (!data.found) {
  return [{ json: { status: 'not_found', message: data.message } }];
}

const lead = data.lead;
const message = [
  `Lead Status for ${lead.name}`,
  `Phone: ${lead.phone}`,
  `Current Status: ${lead.status}`,
  `Interest: ${lead.interest}`,
  `Last Contact: ${lead.lastContact}`,
  `Next Step: ${lead.nextStep}`,
  `Assigned To: ${lead.assignedTo}`
].join('\n');

return [{ json: { status: 'found', message, lead } }];
